module.exports = /*#__PURE__*/JSON.parse('[{"id":"airo","title":"Airo","slug":"airo","description":"Co-Op Advertising Program With Airo Brands To Drive Sell-Thru And Measurable Online Sales","thumbnail":"/brands/Airo-Thumbnail.png","brandLogo":"/brands/Airo-Image.webp","homepageImage":"/brands/Airo-Homepage.png","category":"Retail","results":{"roas":"27.48X","revenue":"$192,290","ctr":"0.15%","visits":"522"},"howItWorks":[{"step":"1. Subscription","title":"Brand funds the display flight","icon":"subscription"},{"step":"2. Delivery","title":"JC delivers best-in-class programmatic display (prospecting, conquesting, retargeting).","icon":"delivery"},{"step":"3. Attribution","title":"JC Pixel attributes SKU- level sales back to media.","icon":"attribution"},{"step":"4. Creative","title":"JointCommerce builds all ad creatives as an added value - approved by Glass Meadows.","icon":"creative"}],"campaignStrategy":{"description":"JointCommerce targeted Airo\'s product shoppers across a curated publisher network, placing Airo\'s products directly in front of high-intent consumers. These shoppers were directed directly to the Airo Brands product pages on partnered retailer online stores, reducing friction in the purchase journey and increasing the likelihood of conversion.","technology":"Our pixel technology continuously identified high-intent consumers who left the site or abandoned their cart and dynamically re-engaged them. This strategy re-engaged potential buyers and guided them back to the exact point where they previously left off.","reporting":"All campaign activity and resulting purchases were reported through the JointCommerce real-time reporting dashboard, enabling SKU-level sales tracking, order ID visibility, and full attribution to media exposure."},"campaignObjective":["Increase sell-through of partnered retailers","Drive measurable online revenue","Reach high-intent consumers","Track sales with closed-loop attribution"],"whyBothWin":{"title":"Why Both Glass Meadows and Partnered Retailers Win","description":"Advertising drives consumer demand for Glass Meadows while retailers gain qualified traffic, new customers, repeat engagement, and faster product sell-through.","benefits":[{"title":"Privacy-First","description":"Retailer retains full data ownership."},{"title":"Media That Moves Units","description":"High-intent placements across ESPN, HGTV, Food Network, HBO Max, Paramount+, NBC, ABC, and more"},{"title":"Net-New Shoppers","description":"A21+ cannabis audiences + mainstream reach drive incremental demand."},{"title":"Closed-Loop Attribution","description":"Measure units, revenue, ROAS,conversions, timestamps, and Order IDs."}]}},{"id":"eureka","title":"Eureka","slug":"eureka","description":"Co-Op Advertising Program With Eureka To Drive Sell-Thru And Measurable Online Sales","thumbnail":"/brands/Eureka-Thumbnail.png","brandLogo":"/brands/Eureka-Logo.png","homepageImage":"/brands/Eureka-Homepage.png","category":"Retail","results":{"roas":"7.47X","revenue":"$47,635","ctr":"0.14%","visits":"432"},"howItWorks":[{"step":"1. Subscription","title":"Brand funds the display flight (monthly subscription).","icon":"subscription"},{"step":"2. Delivery","title":"JC delivers best-in-class programmatic display (prospecting, conquesting, retargeting).","icon":"delivery"},{"step":"3. Attribution","title":"JC Pixel attributes SKU-level sales back to media.","icon":"attribution"},{"step":"4. Creative","title":"JointCommerce builds all ad creatives as an added value - approved by Eureka.","icon":"creative"}],"campaignStrategy":{"description":"JointCommerce geo-targets first-party cannabis shoppers across our curated publisher network on mobile, tablet, and desktop, driving them directly to the Eureka product page on partnered retailers\' online menus.","technology":"Our pixel technology dynamically retargets high-intent shoppers who abandon carts or leave before completing their purchase, bringing them back to their last point of engagement.","reporting":"All Eureka sales are tracked down to the product and order ID within the JointCommerce real-time reporting dashboard."},"campaignObjective":["Increase sell-through of partnered retailers","Drive measurable online revenue","Reach high-intent cannabis consumers","Track sales with closed-loop attribution"],"whyBothWin":{"title":"Why Both Eureka and Partnered Retailers Win","description":"Advertising drives consumer demand for Eureka while retailers gain qualified traffic, new customers, repeat engagement, and faster product sell-through.","benefits":[{"title":"Privacy-First","description":"Retailer retains full data ownership."},{"title":"Media That Moves Units","description":"High-intent placements across ESPN, HGTV, Food Network, HBO Max, Paramount+, NBC, ABC, and more."},{"title":"Net-New Shoppers","description":"A21+ cannabis audiences + mainstream reach drive incremental demand."},{"title":"Closed-Loop Attribution","description":"Measure units, revenue, ROAS, conversions, timestamps, and Order IDs."}]}},{"id":"timeless","title":"Timeless","slug":"timeless","description":"Co-Op Advertising Program With Timeless To Drive Sell-Thru And Measurable Online Sales","thumbnail":"/brands/Timeless-Thumbnail.png","brandLogo":"/brands/Timeless-Logo.png","homepageImage":"/brands/Timeless-Homepage.png","category":"Retail","results":{"roas":"12.49X","revenue":"N/A","ctr":"N/A","visits":"N/A"},"howItWorks":[{"step":"1. Subscription","title":"Brand funds the display flight (monthly subscription).","icon":"subscription"},{"step":"2. Delivery","title":"JC delivers best-in-class programmatic display (prospecting, conquesting, retargeting).","icon":"delivery"},{"step":"3. Attribution","title":"JC Pixel attributes SKU-level sales back to media.","icon":"attribution"},{"step":"4. Creative","title":"JointCommerce builds all ad creatives as an added value - approved by Timeless.","icon":"creative"}],"campaignStrategy":{"description":"JointCommerce geo-targets first-party cannabis shoppers across our curated publisher network on mobile, tablet, and desktop, driving them directly to the Timeless\' product page on partnered retailers\' online menus.","technology":"Our pixel technology dynamically retargets high-intent shoppers who abandon carts or leave before completing their purchase, bringing them back to their last point of engagement.","reporting":"All Timeless sales are tracked down to the product and order ID within the JointCommerce real-time reporting dashboard."},"campaignObjective":["Increase sell-through of partnered retailers","Drive measurable online revenue","Reach high-intent cannabis consumers","Track sales with closed-loop attribution"],"whyBothWin":{"title":"Why Both Timeless and Partnered Retailers Win","description":"Advertising drives consumer demand for Timeless while retailers gain qualified traffic, new customers, repeat engagement, and faster product sell-through.","benefits":[{"title":"Privacy-First","description":"Retailer retains full data ownership."},{"title":"Media That Moves Units","description":"High-intent placements across ESPN, HGTV, Food Network, HBO Max, Paramount+, NBC, ABC, and more."},{"title":"Net-New Shoppers","description":"A21+ cannabis audiences + mainstream reach drive incremental demand."},{"title":"Closed-Loop Attribution","description":"Measure units, revenue, ROAS, conversions, timestamps, and Order IDs."}]}}]');

